final:
module RefModule (
    input [3:0] d,
    input clk,
    input shift_en,
    output reg [3:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (shift_en)
            q <= {1'b0, q[3:1]};
        else
            q <= d;
    end

endmodule
